// newAuthSetupCmd prints concrete steps for getting a credential.
func newAuthSetupCmd(flags *rootFlags) *cobra.Command {
	var launch bool
	cmd := &cobra.Command{
		Use:     "setup",
		Short:   "Print steps for obtaining a credential (use --launch to open the URL)",
		Example: "  qbo-pp-cli auth setup\n  qbo-pp-cli auth setup --launch",
		RunE: func(cmd *cobra.Command, args []string) error {
			if launch {
				cfg, err := config.Load(flags.configPath)
				if err != nil {
					return configErr(err)
				}

				clientID := os.Getenv("QBO_CLIENT_ID")
				if clientID == "" {
					clientID = cfg.ClientID
				}
				clientSecret := os.Getenv("QBO_CLIENT_SECRET")
				if clientSecret == "" {
					clientSecret = cfg.ClientSecret
				}
				if clientID == "" || clientSecret == "" {
					return fmt.Errorf("both QBO_CLIENT_ID and QBO_CLIENT_SECRET environment variables or config keys must be set to run setup --launch")
				}
				cfg.ClientID = clientID
				cfg.ClientSecret = clientSecret
				return startOAuthFlow(cfg, "http://localhost:3456/callback", cmd.OutOrStdout())
			}

			w := cmd.OutOrStdout()
			fmt.Fprintln(w, "To authenticate, you can run the interactive login command:")
			fmt.Fprintln(w, "  qbo-pp-cli auth login --client-id <id> --client-secret <secret>")
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "Or set environment variables and run login:")
			fmt.Fprintln(w, "  export QBO_CLIENT_ID=\"your_client_id\"")
			fmt.Fprintln(w, "  export QBO_CLIENT_SECRET=\"your_client_secret\"")
			fmt.Fprintln(w, "  qbo-pp-cli auth login")
			return nil
		},
	}
	cmd.Flags().BoolVar(&launch, "launch", false, "Open the setup URL in your default browser")
	return cmd
}

